import { useState, useEffect, useCallback } from 'react';

const useFetch = (fetchFunction, dependencies = []) => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Wrap the fetch function in useCallback to properly handle dependencies
  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const result = await fetchFunction();
      // Если результат null, не обновляем данные
      if (result !== null) {
        setData(result);
      }
    } catch (err) {
      console.error('Error in useFetch:', err);
      setError(err);
    } finally {
      setLoading(false);
    }
  }, [fetchFunction]);

  // Initial fetch on mount and when dependencies change
  useEffect(() => {
    let isMounted = true;

    const execute = async () => {
      setLoading(true);
      setError(null);

      try {
        const result = await fetchFunction();
        // Если результат null, не обновляем данные
        if (isMounted && result !== null) {
          setData(result);
        }
      } catch (err) {
        console.error('Error in useFetch effect:', err);
        if (isMounted) {
          setError(err);
        }
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    };

    execute();

    return () => {
      isMounted = false;
    };
  }, [fetchFunction, ...dependencies]);

  return { data, loading, error, refetch: fetchData };
};

export default useFetch;
